export function formatTitle(value, mode = 'plain') {
  if (mode === 'title') return value.toLocaleTitle?.() ? value.toLocaleTitle() : value.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ')
  if (mode === 'upper') return value.toUpperCase()
  if (mode === 'lower') return value.toLowerCase()
  return value
}

